// user.proto — the source of truth. Everything else is generated.
syntax = "proto3";
package user.v1;

option java_package = "com.example.user.v1";
option java_multiple_files = true;

service UserService {
  // Unary
  rpc GetUser(GetUserRequest) returns (User);

  // Server-streaming
  rpc ListUsers(ListUsersRequest) returns (stream User);

  // Client-streaming
  rpc BatchCreate(stream CreateUserRequest) returns (BatchCreateResponse);

  // Bidirectional streaming
  rpc Chat(stream ChatMessage) returns (stream ChatMessage);
}

message GetUserRequest {
  int64 id = 1;
}

message User {
  int64  id    = 1;
  string name  = 2;
  string email = 3;
  int64  created_at_epoch_ms = 4;
}

message ListUsersRequest {
  string search = 1;
  int32  limit  = 2;
}

message CreateUserRequest {
  string name  = 1;
  string email = 2;
}

message BatchCreateResponse {
  repeated User users = 1;
}

message ChatMessage {
  int64  from_user_id = 1;
  string content      = 2;
  int64  timestamp_ms = 3;
}

// Run: protoc --java_out=. --grpc-java_out=. user.proto
//      protoc --dart_out=grpc:. user.proto
// Get typed stubs + messages in every target language.

// SERVER (net.devh.grpc.server, or grpc-java directly)
@GrpcService
public class UserGrpcService extends UserServiceGrpc.UserServiceImplBase {

  private final UserRepository repo;

  public UserGrpcService(UserRepository repo) { this.repo = repo; }

  @Override
  public void getUser(GetUserRequest request, StreamObserver<User> responseObserver) {
    var entity = repo.findById(request.getId())
        .orElseThrow(() -> Status.NOT_FOUND.withDescription("user not found").asRuntimeException());

    var response = User.newBuilder()
        .setId(entity.id)
        .setName(entity.name)
        .setEmail(entity.email)
        .setCreatedAtEpochMs(entity.createdAt.toEpochMilli())
        .build();

    responseObserver.onNext(response);
    responseObserver.onCompleted();
  }

  @Override
  public void listUsers(ListUsersRequest req, StreamObserver<User> observer) {
    // Server-streaming — emit one User per row.
    repo.findMatching(req.getSearch(), req.getLimit()).forEach(entity -> {
      observer.onNext(toProto(entity));
    });
    observer.onCompleted();
  }

  @Override
  public StreamObserver<CreateUserRequest> batchCreate(StreamObserver<BatchCreateResponse> observer) {
    // Client-streaming — collect all requests, then respond once.
    var created = new ArrayList<User>();
    return new StreamObserver<>() {
      @Override public void onNext(CreateUserRequest req) { created.add(toProto(repo.save(fromProto(req)))); }
      @Override public void onError(Throwable t) { observer.onError(t); }
      @Override public void onCompleted() {
        observer.onNext(BatchCreateResponse.newBuilder().addAllUsers(created).build());
        observer.onCompleted();
      }
    };
  }
}

// CLIENT — a Kotlin/Java caller
// Auto-generated stub is drop-in typed.
var channel = ManagedChannelBuilder.forAddress("users.internal", 9000)
    .usePlaintext()   // use TLS in prod!
    .build();

var client = UserServiceGrpc.newBlockingStub(channel);
var user = client.getUser(GetUserRequest.newBuilder().setId(42).build());
System.out.println(user.getName());   // 'Ada'

